// biome-ignore-all lint: NexusWidget registry component from shadcn registry.

import React from "react";

const identiconPalette = [
  "var(--foreground-brand)",
  "#16A34A",
  "#B7791F",
  "#7C3AED",
  "#DB2777",
  "#0891B2",
  "#EA580C",
  "#475569",
];

const hashAddress = (address: string) => {
  let hash = 0;
  for (const char of address.toLowerCase()) {
    hash = (hash << 5) - hash + char.charCodeAt(0);
    hash |= 0;
  }
  return Math.abs(hash);
};

export function AddressIdenticon({
  address,
  size = 18,
}: {
  address: string;
  size?: number;
}) {
  const hash = hashAddress(address);
  const primary = identiconPalette[hash % identiconPalette.length];
  const secondary =
    identiconPalette[Math.floor(hash / 7) % identiconPalette.length];
  const accent =
    identiconPalette[Math.floor(hash / 13) % identiconPalette.length];
  const rotation = hash % 360;

  return (
    <span
      aria-hidden="true"
      style={{
        background: `conic-gradient(from ${rotation}deg, ${primary}, ${secondary}, ${accent}, ${primary})`,
        border: "1px solid #FFFFFE",
        borderRadius: "999px",
        boxShadow: "0 0 0 1px #E8E8E7",
        boxSizing: "border-box",
        display: "inline-block",
        flexShrink: 0,
        height: size,
        width: size,
      }}
    />
  );
}

// biome-ignore-all lint: NexusWidget registry component from shadcn registry.

import Decimal from "decimal.js";
import React, { useMemo } from "react";
import type { UserAsset } from "../../nexus/NexusProvider";
import {
  formatTokenAmountDisplay,
  formatUsdBalanceLabel,
} from "./swap-asset-selector";

interface AmountInputUnifiedProps {
  amount: string;
  disabled?: boolean;
  header?: React.ReactNode;
  maxAvailableAmount?: string;
  onChange: (value: string) => void;
  onCommit?: (value: string) => void;
  tokenIcon?: React.ReactNode;
  /** Label shown beside Balance text, e.g. "USDC" */
  tokenSymbol?: string;
  unifiedBalances?: UserAsset[];
  usdValue?: string;
}

export function AmountInputUnified({
  amount,
  onChange,
  onCommit,
  disabled,
  maxAvailableAmount,
  unifiedBalances,
  tokenIcon,
  usdValue,
  tokenSymbol,
  header,
}: AmountInputUnifiedProps) {
  const handleMax = () => {
    if (!totalBalanceValue) return;
    onChange(totalBalanceValue);
    onCommit?.(totalBalanceValue);
  };

  const isUsdMode = !tokenSymbol;
  const totalBalanceValue = useMemo(() => {
    if (!unifiedBalances || !unifiedBalances.length) return "";
    if (isUsdMode) {
      return unifiedBalances
        .reduce((acc, curr) => acc.add(curr.balanceInFiat ?? 0), new Decimal(0))
        .toDecimalPlaces(8, Decimal.ROUND_DOWN)
        .toFixed();
    }
    return unifiedBalances
      .reduce((acc, curr) => acc.add(curr.balance ?? 0), new Decimal(0))
      .toDecimalPlaces(8, Decimal.ROUND_DOWN)
      .toFixed();
  }, [isUsdMode, unifiedBalances]);
  const totalBalanceLabel = useMemo(() => {
    if (!unifiedBalances || !unifiedBalances.length) return "0";
    if (isUsdMode) {
      const fiatAmount = unifiedBalances.reduce(
        (acc, curr) => acc.add(curr.balanceInFiat ?? 0),
        new Decimal(0)
      );
      return formatUsdBalanceLabel(fiatAmount);
    }
    const amount = unifiedBalances.reduce(
      (acc, curr) => acc.add(curr.balance ?? 0),
      new Decimal(0)
    );
    return formatTokenAmountDisplay(amount);
  }, [isUsdMode, unifiedBalances]);

  return (
    <div
      className="w-full flex flex-col bg-white min-h-[136px] nexus-focus-container"
      style={{
        borderRadius: "10px",
        border: "1px solid var(--border-default, #E8E8E7)",
        boxShadow: "0px 1px 12px 0px #5B5B5B0D",
        background: "#FFFFFF",
      }}
    >
      {header && (
        <div className="w-full border-b border-[#E8E8E7] px-3.5 py-2.5">
          {header}
        </div>
      )}
      <div className="flex-1 w-full flex flex-col items-center justify-center p-3.5 relative">
        {/* Central Input row: large amount + MAX button inline */}
        <div className="flex items-center justify-center w-full gap-x-1.5 mb-1">
          <div
            className="flex items-center justify-center text-center"
            style={{
              fontSize: "28px",
              fontWeight: 500,
              gap: "2px",
            }}
          >
            {tokenIcon ? (
              <div className="flex items-center justify-center mr-2">
                {tokenIcon}
              </div>
            ) : (
              <span className="leading-none text-gray-800 mr-1">$</span>
            )}
            <input
              className="min-w-0 text-start bg-transparent border-none outline-none p-0 focus:ring-0 placeholder:text-gray-300 truncate tabular-nums"
              disabled={disabled}
              inputMode="decimal"
              onBlur={() => onCommit?.(amount)}
              onChange={(e) => {
                let next = e.target.value.replaceAll(/[^0-9.]/g, "");
                const parts = next.split(".");
                if (parts.length > 2)
                  next = parts[0] + "." + parts.slice(1).join("");
                if (next === ".") next = "0.";
                onChange(next);
              }}
              onKeyDown={(e) => {
                if (e.key === "Enter") onCommit?.(amount);
              }}
              placeholder="0"
              style={{
                fontFamily: "'Delight', sans-serif",
                fontWeight: 500,
                fontSize: "28px",
                lineHeight: "100%",
                height: "28px",
                letterSpacing: "2%",
                color: "var(--foreground-primary, #161615)",
                fieldSizing: "content",
                minWidth: "1ch",
                maxWidth: "6ch",
              }}
              type="text"
              value={amount}
            />
          </div>
          {/* MAX button — inline beside the input */}
          <button
            className="shrink-0 focus:opacity-80 disabled:opacity-40 disabled:cursor-not-allowed transition-opacity"
            disabled={disabled || !maxAvailableAmount}
            onClick={handleMax}
            style={{
              background: "var(--background-tertiary, #F0F0EF)",
              width: "36px",
              height: "20px",
              borderRadius: "5px",
              padding: "2px 6px",
              color: "var(--foreground-muted, #848483)",
              fontFamily:
                "var(--font-geist-mono), ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace",
              fontWeight: 400,
              fontSize: "9px",
              lineHeight: "100%",
            }}
          >
            MAX
          </button>
        </div>

        {/* Balance display — below amount + MAX row */}
        {(totalBalanceValue || maxAvailableAmount) && (
          <div className="absolute bottom-3 left-0 w-full flex justify-center">
            <p
              style={{
                color: "var(--widget-card-foreground-muted, #848483)",
                fontFamily:
                  "var(--font-geist-sans), ui-sans-serif, system-ui, sans-serif",
                fontWeight: 400,
                fontSize: "10.5px",
                lineHeight: "100%",
                textAlign: "center",
              }}
            >
              Balance: {totalBalanceLabel || "0"}
              {tokenSymbol ? ` ${tokenSymbol}` : ""}
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

// biome-ignore-all lint: NexusWidget registry component from shadcn registry.

import Decimal from "decimal.js";
import { AlertCircle, ChevronDown, Loader2 } from "lucide-react";
import React, { useRef, useState } from "react";
import { PayWithSources as SharedPayWithSources } from "./pay-with-sources";
import {
  formatSelectedTokenBalanceLabel,
  formatUsdBalanceLabel,
  type SwapTokenOption,
} from "./swap-asset-selector";

interface DepositIdleFormProps {
  amount: string;
  amountMode: "token" | "usd";
  calculatingPercent?: number | null;
  fromTokens: SwapTokenOption[];
  isAmountReadOnly?: boolean;
  isCalculatingMax?: boolean;
  isQuoteRefreshing?: boolean;
  isSourcePickerDisabled?: boolean;
  isTokenPickerDisabled?: boolean;
  hideDestinationTokenDropdownIcon?: boolean;
  onAmountChange: (val: string) => void;
  onAmountModeToggle: () => void;
  onOpenSourcePicker: () => void;
  onOpenTokenPicker?: () => void;
  onSetPercent: (pct: number) => void;
  reserveSourceRows?: boolean;
  routeMessage?: string;
  routeStatus?: "loading" | "insufficient";
  showAutoBadge?: boolean;
  tokenValue: string;
  toToken?: SwapTokenOption;
  totalBalance: string;
  usdValue: string;
}

const uiFont = '"Geist", system-ui, sans-serif';
const primary = "#161615";
const muted = "#848483";
const border = "#E8E8E7";
const brand = "var(--foreground-brand)";

const parseDecimal = (value: unknown) => {
  if (value === null || value === undefined || value === "") return undefined;
  if (Decimal.isDecimal(value)) return value;
  const cleaned = String(value).replace(/[^0-9.-]/g, "");
  if (!cleaned || cleaned === "-" || cleaned === "." || cleaned === "-.") {
    return undefined;
  }
  try {
    const parsed = new Decimal(cleaned);
    return parsed.isFinite() ? parsed : undefined;
  } catch {
    return undefined;
  }
};

const formatToken = (value: unknown) => {
  const amount = parseDecimal(value) ?? new Decimal(0);
  return amount.toDecimalPlaces(8).toFixed();
};

const formatUsd = (value: unknown) => {
  const amount = parseDecimal(value) ?? new Decimal(0);
  if (amount.gt(0) && amount.lt(0.01)) return "<$0.01";
  return `$${amount.toDecimalPlaces(2).toFixed()}`;
};

const MAX_AMOUNT_DISPLAY_DECIMALS = 8;
const getTokenInputDecimals = (token?: Pick<SwapTokenOption, "decimals">) => {
  const decimals = Number(token?.decimals);
  return Number.isFinite(decimals) && decimals >= 0 ? Math.floor(decimals) : 18;
};

const formatAmountInputDisplay = (value: string) => {
  if (!value) return "";
  try {
    return new Decimal(value)
      .toDecimalPlaces(MAX_AMOUNT_DISPLAY_DECIMALS, Decimal.ROUND_DOWN)
      .toFixed();
  } catch {
    return value;
  }
};

const sanitizeAmountInput = (raw: string, maxDecimals: number) => {
  let next = raw.replaceAll(/[^0-9.]/g, "");
  const parts = next.split(".");
  if (parts.length > 2) next = parts[0] + "." + parts.slice(1).join("");
  const [integerPart, decimalPart] = next.split(".");
  if (decimalPart !== undefined) {
    next = `${integerPart}.${decimalPart.slice(0, Math.max(0, maxDecimals))}`;
  }
  if (next === ".") next = "0.";
  return next;
};

function TokenLogo({
  src,
  label,
  size = 30,
  fontSize = 12,
  style,
}: {
  src?: string;
  label?: string;
  size?: number;
  fontSize?: number;
  style?: React.CSSProperties;
}) {
  const [failed, setFailed] = useState(!src);

  React.useEffect(() => {
    setFailed(!src);
  }, [src]);

  if (!failed && src) {
    return (
      <img
        alt={label || ""}
        onError={() => setFailed(true)}
        src={src}
        style={{
          backgroundColor: "#FFFFFE",
          borderRadius: "999px",
          height: size,
          objectFit: "cover",
          width: size,
          ...style,
        }}
      />
    );
  }

  return (
    <div
      style={{
        alignItems: "center",
        backgroundColor: "#E8F0FF",
        borderRadius: "999px",
        color: brand,
        display: "flex",
        fontFamily: uiFont,
        fontSize,
        fontWeight: 700,
        height: size,
        justifyContent: "center",
        width: size,
        ...style,
      }}
    >
      {(label || "?").slice(0, 1).toUpperCase()}
    </div>
  );
}

function SourceLogoPair({ token }: { token: SwapTokenOption }) {
  return (
    <div style={{ flexShrink: 0, height: 32, position: "relative", width: 32 }}>
      <TokenLogo label={token.symbol} size={32} src={token.logo} />
      {token.chainLogo && (
        <TokenLogo
          label={token.chainName}
          size={14}
          src={token.chainLogo}
          style={{
            bottom: -2,
            outline: "1px solid #FFFFFE",
            position: "absolute",
            right: -2,
          }}
        />
      )}
    </div>
  );
}

function ExactOutPercentButtons({
  visible,
  onSelect,
}: {
  visible: boolean;
  onSelect: (pct: number) => void;
}) {
  const [focusedPercent, setFocusedPercent] = useState<number | null>(null);

  React.useEffect(() => {
    if (!visible) setFocusedPercent(null);
  }, [visible]);

  return (
    <div
      style={{
        alignItems: "center",
        boxSizing: "border-box",
        display: "flex",
        gap: "6px",
        opacity: visible ? 1 : 0,
        pointerEvents: visible ? "auto" : "none",
        transition: "opacity 0.18s ease-out",
        width: "100%",
      }}
    >
      {[25, 50, 75, 100].map((pct) => {
        const isMax = pct === 100;
        const isFocused = focusedPercent === pct;
        return (
          <button
            key={pct}
            onClick={(e) => {
              e.stopPropagation();
              onSelect(pct);
            }}
            onBlur={() => setFocusedPercent(null)}
            onFocus={() => setFocusedPercent(pct)}
            style={{
              alignItems: "center",
              backgroundColor: isFocused ? "#E8F0FF" : "#F4F4F3",
              border: "none",
              borderRadius: "8px",
              boxSizing: "border-box",
              color: isFocused ? brand : "#363635",
              cursor: "pointer",
              display: "flex",
              flex: "1 1 0%",
              fontFamily: '"Geist", system-ui, sans-serif',
              fontSize: "12px",
              fontWeight: 500,
              justifyContent: "center",
              lineHeight: "20px",
              minWidth: 0,
              paddingBlock: "5px",
              paddingInline: "10px",
            }}
            type="button"
          >
            {isMax ? "MAX" : `${pct}%`}
          </button>
        );
      })}
    </div>
  );
}

function SkeletonRow() {
  return (
    <div
      style={{
        alignItems: "center",
        display: "flex",
        justifyContent: "space-between",
      }}
    >
      <div
        className="animate-pulse"
        style={{
          background:
            "linear-gradient(90deg, #F0F0EF 0%, #F7F7F6 48%, #F0F0EF 100%)",
          backgroundSize: "200% 100%",
          borderRadius: "6px",
          height: "32px",
          width: "128px",
        }}
      />
      <div
        className="animate-pulse"
        style={{
          background:
            "linear-gradient(90deg, #F0F0EF 0%, #F7F7F6 48%, #F0F0EF 100%)",
          backgroundSize: "200% 100%",
          borderRadius: "999px",
          height: "32px",
          width: "108px",
        }}
      />
    </div>
  );
}

function PayWithSources({
  fromTokens,
  onOpenSourcePicker,
  routeStatus,
  routeMessage,
}: {
  fromTokens: SwapTokenOption[];
  onOpenSourcePicker: () => void;
  routeStatus?: "loading" | "insufficient";
  routeMessage?: string;
}) {
  const scrollRef = useRef<HTMLDivElement | null>(null);
  const isRouteLoading = routeStatus === "loading";
  const shouldShowSourceSummary = !isRouteLoading && fromTokens.length > 0;
  const shouldScroll = shouldShowSourceSummary && fromTokens.length > 3;
  const autoBadge = (
    <span
      style={{
        border: `1px solid ${brand}`,
        borderRadius: "999px",
        color: brand,
        fontFamily: uiFont,
        fontSize: "9px",
        fontWeight: 600,
        letterSpacing: "0.04em",
        lineHeight: "14px",
        padding: "1px 5px",
      }}
    >
      AUTO
    </span>
  );

  return (
    <div
      style={{
        backgroundColor: "#FFFFFE",
        border: `1px solid ${border}`,
        borderRadius: "12px",
        boxShadow: "#1616150A 0px 1px 2px",
        boxSizing: "border-box",
        display: "flex",
        flexDirection: "column",
        gap: "10px",
        padding: "14px",
      }}
    >
      <div
        style={{
          alignItems: "center",
          display: "flex",
          justifyContent: "space-between",
        }}
      >
        <div
          style={{
            alignItems: "center",
            color: muted,
            display: "flex",
            fontFamily: uiFont,
            fontSize: "14px",
            fontWeight: 500,
            gap: "6px",
            letterSpacing: "0.08em",
            lineHeight: "20px",
            textTransform: "uppercase",
          }}
        >
          <span>
            Pay With
            {shouldShowSourceSummary ? ` · ${fromTokens.length} assets` : ""}
          </span>
          {autoBadge}
        </div>
        {shouldShowSourceSummary && (
          <button
            onClick={onOpenSourcePicker}
            style={{
              backgroundColor: "#F4F7FE",
              border: "none",
              borderRadius: "6px",
              color: brand,
              cursor: "pointer",
              fontFamily: uiFont,
              fontSize: "14px",
              fontWeight: 500,
              lineHeight: "16px",
              padding: "7px 10px",
            }}
          >
            Edit tokens
          </button>
        )}
      </div>

      {isRouteLoading ? (
        <>
          <SkeletonRow />
          <div
            style={{
              alignItems: "center",
              color: brand,
              display: "flex",
              fontFamily: uiFont,
              fontSize: "15px",
              gap: "6px",
            }}
          >
            <Loader2
              className="animate-spin"
              style={{ height: 13, width: 13 }}
            />
            Calculating best route...
          </div>
        </>
      ) : shouldShowSourceSummary ? (
        <div style={{ position: "relative" }}>
          <div
            ref={scrollRef}
            style={{
              display: "flex",
              flexDirection: "column",
              maxHeight: shouldScroll ? "184px" : undefined,
              overflowY: shouldScroll ? "auto" : undefined,
              paddingRight: shouldScroll ? "6px" : 0,
            }}
          >
            {fromTokens.map((token, index) => (
              <div
                key={`${token.contractAddress}-${token.chainId ?? "unified"}-${index}`}
                style={{
                  alignItems: "center",
                  borderTop: index === 0 ? "none" : "1px solid #F0F0EF",
                  display: "flex",
                  justifyContent: "space-between",
                  minHeight: "52px",
                  padding: "6px 0",
                }}
              >
                <div
                  style={{
                    alignItems: "center",
                    display: "flex",
                    gap: "10px",
                    minWidth: 0,
                  }}
                >
                  <SourceLogoPair token={token} />
                  <div
                    style={{
                      display: "flex",
                      flexDirection: "column",
                      gap: "3px",
                      minWidth: 0,
                    }}
                  >
                    <span
                      style={{
                        color: primary,
                        fontFamily: uiFont,
                        fontSize: "16px",
                        fontWeight: 600,
                      }}
                    >
                      {token.symbol}
                    </span>
                    <span
                      style={{
                        color: muted,
                        fontFamily: uiFont,
                        fontSize: "14px",
                        overflow: "hidden",
                        textOverflow: "ellipsis",
                        whiteSpace: "nowrap",
                      }}
                    >
                      {token.isUnified
                        ? "Unified balance"
                        : `on ${token.chainName || "Unknown chain"}`}
                    </span>
                  </div>
                </div>
                <div
                  style={{
                    display: "flex",
                    flexDirection: "column",
                    gap: "3px",
                    textAlign: "right",
                  }}
                >
                  <span
                    style={{
                      color: primary,
                      fontFamily: uiFont,
                      fontSize: "15px",
                    }}
                  >
                    {formatToken(token.userAmount || token.balance)}{" "}
                    {token.symbol}
                  </span>
                  <span
                    style={{
                      color: muted,
                      fontFamily: uiFont,
                      fontSize: "14px",
                    }}
                  >
                    {formatUsd(token.userAmountUsd || token.balanceInFiat)}
                  </span>
                </div>
              </div>
            ))}
          </div>
          {shouldScroll && (
            <button
              aria-label="Scroll payment sources"
              onClick={() =>
                scrollRef.current?.scrollBy({ behavior: "smooth", top: 64 })
              }
              style={{
                alignItems: "center",
                background: "#FFFFFE",
                border: `1px solid ${border}`,
                borderRadius: "999px",
                bottom: "4px",
                boxShadow: "0 2px 8px rgba(22,22,21,0.08)",
                cursor: "pointer",
                display: "flex",
                height: "22px",
                justifyContent: "center",
                left: "50%",
                padding: 0,
                position: "absolute",
                transform: "translateX(-50%)",
                width: "22px",
              }}
              type="button"
            >
              <ChevronDown style={{ color: muted, height: 14, width: 14 }} />
            </button>
          )}
        </div>
      ) : (
        <div
          style={{
            color: primary,
            fontFamily: uiFont,
            fontSize: "15px",
            lineHeight: "20px",
          }}
        >
          Sources will be auto selected
        </div>
      )}

      {routeStatus === "insufficient" && routeMessage && (
        <div
          style={{
            alignItems: "center",
            color: "#D32F2F",
            display: "flex",
            fontFamily: uiFont,
            fontSize: "15px",
            gap: "8px",
            lineHeight: "20px",
          }}
        >
          <AlertCircle style={{ flexShrink: 0, height: 15, width: 15 }} />
          {routeMessage}
        </div>
      )}
    </div>
  );
}

export function DepositIdleForm({
  amount,
  amountMode,
  onAmountChange,
  onAmountModeToggle,
  toToken,
  totalBalance,
  usdValue,
  tokenValue,
  fromTokens,
  onOpenSourcePicker,
  onSetPercent,
  routeStatus,
  routeMessage,
  isAmountReadOnly = false,
  isCalculatingMax,
  calculatingPercent,
  isQuoteRefreshing,
  hideDestinationTokenDropdownIcon = false,
  showAutoBadge = true,
  isSourcePickerDisabled = false,
  isTokenPickerDisabled = false,
  onOpenTokenPicker,
  reserveSourceRows = false,
}: DepositIdleFormProps) {
  const [pendingPercent, setPendingPercent] = useState<number | null>(null);
  const [isAmountFocused, setIsAmountFocused] = useState(false);

  React.useEffect(() => {
    if (!isCalculatingMax) setPendingPercent(null);
  }, [isCalculatingMax]);

  const handlePercentSelect = (pct: number) => {
    setPendingPercent(pct);
    onSetPercent(pct);
  };

  const handleInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (isAmountReadOnly) return;
    onAmountChange(
      sanitizeAmountInput(
        e.target.value,
        isUsdMode
          ? MAX_AMOUNT_DISPLAY_DECIMALS
          : getTokenInputDecimals(toToken),
      ),
    );
  };
  const isUsdMode = amountMode === "usd";
  const amountDisplayValue = isAmountFocused
    ? amount
    : formatAmountInputDisplay(amount);
  const showTokenPickerDropdownIcon =
    Boolean(onOpenTokenPicker) &&
    !isTokenPickerDisabled &&
    !hideDestinationTokenDropdownIcon;
  const activePendingPercent =
    calculatingPercent ?? (isCalculatingMax ? pendingPercent : null);
  const isMaxCalculating = Boolean(
    isCalculatingMax && activePendingPercent === 100,
  );
  const destinationBalanceLabel = isUsdMode
    ? formatUsdBalanceLabel(toToken?.balanceInFiat)
    : formatSelectedTokenBalanceLabel(toToken) ||
      `0 ${toToken?.symbol || ""}`.trim();

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        gap: "10px",
        width: "100%",
      }}
    >
      <div
        className="nexus-focus-container"
        style={{
          backgroundColor: "#FFFFFE",
          borderColor: border,
          borderRadius: "14px",
          borderStyle: "solid",
          borderWidth: "1px",
          boxShadow: "#1616150A 0px 1px 2px",
          boxSizing: "border-box",
          display: "flex",
          flexDirection: "column",
