/** Reusable percentage quick-select buttons row with transition wrapper */
function PercentButtons({
  visible,
  onSelect,
  maxLabel = "Max",
}: {
  visible: boolean;
  onSelect: (pct: number) => void;
  maxLabel?: string;
}) {
  const [hoveredPct, setHoveredPct] = useState<number | null>(null);

  return (
    <div
      style={{
        alignItems: "center",
        backgroundColor: "#F0F3F9",
        borderRadius: "6px",
        boxShadow: "#2A388B0F 0px 1px 2px inset",
        boxSizing: "border-box",
        display: "flex",
        flexShrink: 0,
        gap: "2px",
        padding: "2px",
        opacity: visible ? 1 : 0,
        visibility: visible ? "visible" : "hidden",
        pointerEvents: visible ? "auto" : "none",
        transition: "opacity 0.18s ease-out, visibility 0.18s ease-out",
        width: "97px",
      }}
    >
      {[20, 50, 100].map((pct) => {
        const label = pct === 100 ? maxLabel : `${pct}%`;
        const isHovered = hoveredPct === pct;

        return (
          <button
            key={pct}
            onClick={(e) => {
              e.stopPropagation();
              onSelect(pct);
            }}
            onMouseDown={(e) => {
              e.preventDefault();
            }}
            onMouseEnter={() => setHoveredPct(pct)}
            onMouseLeave={() => setHoveredPct(null)}
            style={{
              alignItems: "center",
              backgroundColor: isHovered ? "#FFFFFF" : "transparent",
              borderRadius: "4px",
              boxShadow: isHovered ? "#3C286414 0px 1px 2px" : "none",
              boxSizing: "border-box",
              color: isHovered ? "#1F1F1F" : "#8E8E89",
              cursor: "pointer",
              display: "flex",
              fontFamily: '"Geist", system-ui, sans-serif',
              fontSize: "10px",
              fontWeight: 500,
              height: "18px",
              justifyContent: "center",
              flex: "1 1 0%",
              minWidth: 0,
              paddingInline: "3px",
              border: "none",
              transition: "all 0.15s ease-out",
            }}
            tabIndex={-1}
            type="button"
          >
            {label}
          </button>
        );
      })}
    </div>
  );
}

function UnifiedTokenLogoBadge({
  token,
  size = 24,
}: {
  token: SwapTokenOption;
  size?: number;
}) {
  const [popover, setPopover] = useState<{
    left: number;
    top: number;
    width: number;
    maxHeight: number;
  } | null>(null);
  const triggerRef = useRef<HTMLDivElement | null>(null);
  const sources = token.sourceTokens ?? [];
  const chainCount =
    new Set(
      sources
        .map((source) => source.chainId ?? source.chainName)
        .filter(Boolean),
    ).size || sources.length;

  const showPopover = () => {
    const rect = triggerRef.current?.getBoundingClientRect();
    if (!rect || typeof window === "undefined") return;
    const width = 250;
    const maxHeight = 260;
    const viewportPadding = 8;
    const left = Math.min(
      Math.max(viewportPadding, rect.right - width),
      window.innerWidth - width - viewportPadding,
    );
    const belowTop = rect.bottom + 8;
    const top =
      belowTop + maxHeight > window.innerHeight
        ? Math.max(viewportPadding, rect.top - maxHeight - 8)
        : belowTop;
    setPopover({ left, top, width, maxHeight });
  };

  return (
    <div
      onMouseEnter={showPopover}
      onMouseLeave={() => setPopover(null)}
      ref={triggerRef}
      style={{
        boxSizing: "border-box",
        flexShrink: 0,
        height: `${size}px`,
        position: "relative",
        width: `${size}px`,
      }}
    >
      <LogoCircle
        alt={token.symbol}
        fontSize={Math.max(9, Math.floor(size / 2))}
        label={token.symbol}
        size={size}
        src={token.logo}
