  ENZOBTC: "BTC",
  KBTC: "BTC",
  BBTC: "BTC",
  SYBTC: "BTC",
  "WBTC.E": "BTC",

  // --- ETH derivatives ---
  STETH: "ETH",
  RETH: "ETH",
  WSTETH: "ETH",
  WBETH: "ETH",
  WEETH: "ETH",
  GTETH: "ETH",
  CBETH: "ETH",

  // --- Other wrapped natives ---
  WSOL: "SOL",
  WTRX: "TRX",
  WBNB: "BNB",
  WHYPE: "HYPE",
  WAVAX: "AVAX",

  // --- Stablecoin variants ---
